public function testExportHeader(): void
{
    $GLOBALS['crlf'] = "\n";

    $this->expectOutputString(
        "[\n"
        . '{"type":"header","version":"' . Version::VERSION
        . '","comment":"Export to JSON plugin for phpMyAdmin"},'
        . "\n"
    );

    self::assertTrue($this->object->exportHeader());
}
